    ('Fighter: Two Extra Attacks', 'You can attack three times instead of once whenever you take the Attack action.'),
    ('Fighter: Weapon Mastery', 'Use mastery properties for three Simple or Martial weapons, changing one choice after each Long Rest. More weapon choices unlock at higher Fighter levels.'),
    ('Monk (Warrior of Mercy): Flurry of Healing and Harm', 'When using Flurry of Blows, replace any strikes with Hand of Healing for no Focus cost and use Hand of Harm once without spending Focus. Uses equal Wisdom modifier per Long Rest.'),
    ('Monk (Warrior of Mercy): Hand of Harm', 'Once per turn when you hit with an Unarmed Strike and deal damage, spend 1 Focus Point to deal extra Necrotic damage equal to one Martial Arts die plus Wisdom.'),
    ('Monk (Warrior of Mercy): Hand of Healing', 'Magic Action to spend 1 Focus Point and touch a creature, restoring HP equal to one Martial Arts die plus Wisdom. When using Flurry of Blows, replace one strike with this healing for no Focus cost.'),
    ('Monk (Warrior of Mercy): Hand of Ultimate Mercy', 'Magic Action to touch a creature that died within 24 hours and spend 5 Focus Points, returning it to life with 4d10 + Wisdom HP and removing certain conditions. Once per Long Rest.'),
    ('Monk (Warrior of Mercy): Implements of Mercy', 'Gain proficiency in Insight, Medicine, and Herbalism Kit. You gain a special mask.'),
    ('Monk (Warrior of Mercy): Physician''s Touch', 'Hand of Healing ends Blinded, Deafened, Paralyzed, Poisoned, or Stunned. Hand of Harm Poisons target.'),
    ('Monk (Warrior of Shadow): Cloak of Shadows', 'Magic Action while in dim light or darkness to spend 3 Focus Points and become shrouded for 1 minute, gaining Invisibility, partial incorporeality, and free Flurry of Blows.'),
    ('Monk (Warrior of Shadow): Improved Shadow Step', 'When using Shadow Step, spend 1 Focus Point to ignore the dim light or darkness requirement for that teleport and make an Unarmed Strike as part of the Bonus Action.'),
    ('Monk (Warrior of Shadow): Shadow Arts', 'Gain Darkvision, learn Minor Illusion using Wisdom, and spend 1 Focus Point to cast Darkness without components. You can see through this Darkness and move it at the start of your turns.'),
    ('Monk (Warrior of Shadow): Shadow Step', 'Bonus Action to teleport up to 60ft between areas of dim light or darkness. Gain Advantage on next attack.'),
    ('Monk (Warrior of the Elements): Elemental Attunement', 'At the start of your turn, spend 1 Focus Point to imbue yourself for 10 minutes. Your Unarmed Strikes gain 10-foot extra reach, can deal Acid, Cold, Fire, Lightning, or Thunder damage, and can pull or push targets.'),
    ('Monk (Warrior of the Elements): Elemental Burst', 'Magic Action to spend 2 Focus Points and create a 20-foot-radius sphere within 120 feet, dealing three Martial Arts dice of Acid, Cold, Fire, Lightning, or Thunder damage on a failed Dexterity save.'),
    ('Monk (Warrior of the Elements): Elemental Epitome', 'While Elemental Attunement is active, gain changeable elemental Resistance, damage nearby creatures during Step of the Wind, and add one Martial Arts die of elemental damage once per turn.'),
    ('Monk (Warrior of the Elements): Manipulate Elements', 'You know the Elementalism spell, using Wisdom as your spellcasting ability.'),
    ('Monk (Warrior of the Elements): Stride of the Elements', 'While Elemental Attunement is active, you gain a Fly Speed and Swim Speed equal to your Speed.'),
    ('Monk (Warrior of the Open Hand): Fleet Step', 'When you take a Bonus Action other than Step of the Wind, you can also use Step of the Wind immediately after that Bonus Action.'),
    ('Monk (Warrior of the Open Hand): Open Hand Technique', 'When you hit with an attack from Flurry of Blows, impose Addle to prevent Opportunity Attacks, Push up to 15 feet on a failed Strength save, or Topple on a failed Dexterity save.'),
    ('Monk (Warrior of the Open Hand): Quivering Palm', 'When you hit with an Unarmed Strike, spend 4 Focus Points to set vibrations lasting days equal to your Monk level. End them later to force a Constitution save for 10d12 Force damage, or half on success.'),
    ('Monk (Warrior of the Open Hand): Wholeness of Body', 'Bonus Action to regain HP equal to one Martial Arts die plus Wisdom modifier. Uses equal Wisdom modifier per Long Rest.'),
    ('Monk: Acrobatic Movement', 'You can move along vertical surfaces and across liquids on your turn without falling.'),
    ('Monk: Body and Mind', 'Your Dexterity and Wisdom scores increase by 4, up to a maximum of 25.'),
    ('Monk: Deflect Attacks', 'Reaction when an attack hits you and deals Bludgeoning, Piercing, or Slashing damage, reducing the damage by 1d10 + Dexterity modifier + Monk level. If reduced to 0, spend Focus to redirect it.'),
    ('Monk: Deflect Energy', 'You can use your Deflect Attacks feature against any damage type, not just Physical.'),
    ('Monk: Disciplined Survivor', 'Gain proficiency in all saving throws. If you fail a save, spend Focus to reroll.'),
    ('Monk: Empowered Strikes', 'Whenever you deal damage with an Unarmed Strike, it can deal Force damage or its normal damage type.'),
    ('Monk: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Monk: Evasion', 'You can nimbly dodge out of the way of certain area effects.'),
    ('Monk: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action on your turn.'),
    ('Monk: Heightened Focus', 'Improve your core Focus options: Flurry of Blows makes three strikes, Patient Defense grants Temporary Hit Points, and Step of the Wind can move a nearby willing creature with you.'),
    ('Monk: Martial Arts', 'While unarmed or using Monk weapons without armor or a Shield, make an Unarmed Strike as a Bonus Action, use your Martial Arts die for damage, and use Dexterity for attacks, damage, Grapple DCs, and Shove DCs.'),
    ('Monk: Monk''s Focus', 'Gain Focus Points equal to your Monk level, refreshing on a Short or Long Rest. Spend them on Flurry of Blows, Patient Defense, Step of the Wind, and other Monk features.'),
    ('Monk: Perfect Focus', 'When you roll Initiative and do not use Uncanny Metabolism, regain expended Focus Points until you have 4 if you had 3 or fewer.'),
    ('Monk: Self-Restoration', 'At the end of each of your turns, remove Charmed, Frightened, or Poisoned from yourself. Forgoing food and drink no longer gives you Exhaustion.'),
    ('Monk: Slow Fall', 'You can use your reaction when you fall to reduce any falling damage you take.'),
    ('Monk: Stunning Strike', 'Once per turn when you hit with a Monk weapon or Unarmed Strike, spend 1 Focus Point to force a Constitution save. On a failure, the target is Stunned until your next turn; on a success, its Speed is halved and the next attack against it has Advantage.'),
    ('Monk: Superior Defense', 'At the start of your turn, spend 3 Focus Points to gain Resistance to all damage except Force for 1 minute or until Incapacitated.'),
    ('Monk: Unarmored Defense', 'While not wearing armor or a shield, your AC equals 10 + Dexterity + Wisdom.'),
    ('Monk: Unarmored Movement', 'Your speed increases while you are not wearing armor or a shield.'),
    ('Monk: Uncanny Metabolism', 'Once per Long Rest when you roll Initiative, regain all expended Focus Points and regain HP equal to your Monk level plus one roll of your Martial Arts die.'),
    ('Paladin (Oath of Devotion): Aura of Devotion', 'You and allies have Immunity to Charmed while in your Aura of Protection.'),
    ('Paladin (Oath of Devotion): Holy Nimbus', 'Bonus Action to empower your Aura of Protection for 10 minutes with sunlight, Radiant damage to enemies that start there, and Advantage on saves forced by Fiends or Undead.'),
    ('Paladin (Oath of Devotion): Oath of Devotion Spells', 'Always prepare Protection from Evil and Good and Shield of Faith; later add Aid, Zone of Truth, Beacon of Hope, Dispel Magic, Freedom of Movement, Guardian of Faith, Commune, and Flame Strike.'),
    ('Paladin (Oath of Devotion): Sacred Weapon', 'When you take the Attack action, expend Channel Divinity to imbue one held Melee weapon for 10 minutes. Add Charisma to attack rolls, deal normal or Radiant damage, and emit bright holy light.'),
    ('Paladin (Oath of Devotion): Smite of Protection', 'Whenever you cast Divine Smite, you and allies have Half Cover while in your Aura of Protection until the start of your next turn.'),
    ('Paladin (Oath of Glory): Aura of Alacrity', 'Your Speed increases by 10 feet. Allies gain +10 feet of Speed until the end of their next turn when they enter or start in your Aura of Protection.'),
    ('Paladin (Oath of Glory): Glorious Defense', 'Reaction to add your CHA modifier to the AC of you or an ally, potentially causing a miss; then counterattack.'),
    ('Paladin (Oath of Glory): Inspiring Smite', 'Immediately after casting Divine Smite, expend Channel Divinity to distribute 2d8 + Paladin level Temporary Hit Points among creatures within 30 feet.'),
    ('Paladin (Oath of Glory): Living Legend', 'Bonus Action to become a living legend for 10 minutes, gaining Advantage on Charisma checks, a saving throw reroll Reaction, and one weapon miss turned into a hit each turn.'),
    ('Paladin (Oath of Glory): Oath of Glory Spells', 'Always prepare Guiding Bolt and Heroism; later add Enhance Ability, Magic Weapon, Haste, Protection from Energy, Compulsion, Freedom of Movement, Legend Lore, and Yolande''s Regal Presence.'),
    ('Paladin (Oath of Glory): Peerless Athlete', 'Bonus Action using Channel Divinity to gain Advantage on Athletics and Acrobatics checks for 1 hour, and increase long and high jumps by 10 feet.'),
    ('Paladin (Oath of Vengeance): Avenging Angel', 'Bonus Action to gain spectral wings, a 60-foot Fly Speed with hover, and an Aura of Protection that can Frighten enemies and grant Advantage on attacks against them.'),
    ('Paladin (Oath of Vengeance): Oath of Vengeance Spells', 'Always prepare Bane and Hunter''s Mark; later add Hold Person, Misty Step, Haste, Protection from Energy, Banishment, Dimension Door, Hold Monster, and Scrying.'),
    ('Paladin (Oath of Vengeance): Relentless Avenger', 'When you hit a creature with an Opportunity Attack, reduce its Speed to 0 until the end of the turn and move up to half your Speed without provoking Opportunity Attacks.'),
    ('Paladin (Oath of Vengeance): Soul of Vengeance', 'Immediately after the target of your Vow of Enmity hits or misses with an attack roll, use your Reaction to make a melee attack against it if it is within range.'),
    ('Paladin (Oath of Vengeance): Vow of Enmity', 'When you take the Attack action, expend Channel Divinity to vow against a visible creature within 30 feet. Gain Advantage on attacks against it for 1 minute, and transfer the vow if it drops to 0 HP.'),
    ('Paladin (Oath of the Ancients): Aura of Warding', 'You and allies have Resistance to Necrotic, Psychic, and Radiant damage while in your Aura of Protection.'),
    ('Paladin (Oath of the Ancients): Elder Champion', 'Bonus Action to empower your Aura of Protection for 1 minute, giving enemies Disadvantage against your spells and Channel Divinity, restoring 10 HP each turn, and letting you cast action spells as Bonus Actions.'),
    ('Paladin (Oath of the Ancients): Nature''s Wrath', 'Magic Action using Channel Divinity to conjure spectral vines. Chosen creatures within 15 feet must make a Strength save or be Restrained for 1 minute, repeating the save at the end of each turn.'),
    ('Paladin (Oath of the Ancients): Oath of the Ancients Spells', 'Always prepare Ensnaring Strike and Speak with Animals; later add Misty Step, Moonbeam, Plant Growth, Protection from Energy, Ice Storm, Stoneskin, Commune with Nature, and Tree Stride.'),
    ('Paladin (Oath of the Ancients): Undying Sentinel', 'When you are reduced to 0 HP and not killed outright, drop to 1 HP and regain HP equal to three times your Paladin level. You also cease visibly aging and cannot be aged magically.'),
    ('Paladin: Abjure Foes', 'Magic Action using Channel Divinity to target creatures up to your Charisma modifier within 60 feet. On a failed Wisdom save, each target is Frightened and limited to movement, an action, or a Bonus Action each turn until it takes damage.'),
    ('Paladin: Aura Expansion', 'The range of your Auras increases to 30ft.'),
    ('Paladin: Aura of Courage', 'You and allies have Immunity to Frightened while in your Aura of Protection.'),
    ('Paladin: Aura of Protection', 'You and allies in your 10-foot Aura of Protection gain a bonus to saving throws equal to your Charisma modifier, minimum +1. The aura is inactive while you are Incapacitated.'),
    ('Paladin: Channel Divinity', 'Channel divine energy to fuel Divine Sense and your oath''s Channel Divinity options. Regain one expended use on a Short Rest and all uses on a Long Rest.'),
    ('Paladin: Divine Sense', 'Bonus Action using Channel Divinity to detect Celestials, Fiends, Undead, and consecrated or desecrated places or objects within 60 feet for 10 minutes.'),
    ('Paladin: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Paladin: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action.'),
    ('Paladin: Faithful Steed', 'Always prepare Find Steed. You can cast it once without expending a spell slot, regaining that free casting after a Long Rest.'),
    ('Paladin: Fighting Style', 'Gain a Fighting Style feat of your choice, or choose Blessed Warrior to learn two Cleric cantrips using Charisma.'),
    ('Paladin: Lay On Hands', 'Bonus Action to touch a creature and restore HP from a pool equal to 5 times your Paladin level. Spend 5 points from the pool to remove Poisoned instead of restoring HP.'),
    ('Paladin: Paladin''s Smite', 'Always prepare Divine Smite. You can cast it once without expending a spell slot, regaining that free casting after a Long Rest.'),
    ('Paladin: Radiant Strikes', 'When you hit with a Melee weapon or Unarmed Strike, the target takes an extra 1d8 Radiant damage.'),
    ('Paladin: Restoring Touch', 'When you use Lay On Hands, spend 5 points from the healing pool per condition to remove Blinded, Charmed, Deafened, Frightened, Paralyzed, or Stunned.'),
    ('Paladin: Spellcasting', 'Cast prepared Paladin spells using Charisma. You start with two level 1 prepared Paladin spells, and use a Holy Symbol as a spellcasting focus.'),
    ('Paladin: Weapon Mastery', 'Use mastery properties for two weapons with which you have proficiency, changing your choices after each Long Rest.'),
    ('Ranger (Beast Master): Bestial Fury', 'When you command your Primal Companion to take Beast''s Strike, it strikes twice. The first time each turn it hits your Hunter''s Mark target, it deals extra Force damage equal to the spell''s bonus damage.'),
    ('Ranger (Beast Master): Exceptional Training', 'When you command your Primal Companion with a Bonus Action, also command it to Dash, Disengage, Dodge, or Help as its Bonus Action. Its attacks can deal Force damage.'),
    ('Ranger (Beast Master): Primal Companion', 'Magically summon a Beast of the Land, Sea, or Sky. It acts during your turn, obeys your commands, and can be commanded with a Bonus Action or by sacrificing one of your attacks.'),
    ('Ranger (Beast Master): Share Spells', 'When you cast a spell targeting yourself, you can also affect your Primal Companion if it is within 30 feet.'),
    ('Ranger (Fey Wanderer): Beguiling Twist', 'Gain Advantage on saves to avoid or end Charmed or Frightened. When a visible creature succeeds on such a save, use a Reaction to force another visible creature within 120 feet to save or become Charmed or Frightened.'),
    ('Ranger (Fey Wanderer): Dreadful Strikes', 'Once per turn when you hit a creature with a weapon, deal extra Psychic damage. The damage increases at Ranger level 11.'),
    ('Ranger (Fey Wanderer): Fey Reinforcements', 'Cast Summon Fey without a Material component, and once per Long Rest without a spell slot. When casting it, you can remove Concentration for that casting and reduce its duration to 1 minute.'),
    ('Ranger (Fey Wanderer): Fey Wanderer Spells', 'Always prepare Charm Person; later add Misty Step, Summon Fey, Dimension Door, and Mislead.'),
    ('Ranger (Fey Wanderer): Misty Wanderer', 'Cast Misty Step without a spell slot a number of times equal to your Wisdom modifier per Long Rest. Whenever you cast it, bring one willing nearby creature with you.'),
    ('Ranger (Fey Wanderer): Otherworldly Glamour', 'Add your Wisdom modifier to Charisma checks, minimum +1, and gain proficiency in Deception, Performance, or Persuasion.'),
    ('Ranger (Gloom Stalker): Dread Ambusher', 'Add Wisdom to Initiative, gain +10 feet of Speed on your first turn of each combat, and use Dreadful Strike to deal Psychic damage a limited number of times per Long Rest.'),
    ('Ranger (Gloom Stalker): Gloom Stalker Spells', 'Always prepare Disguise Self; later add Rope Trick, Fear, Greater Invisibility, and Seeming.'),
    ('Ranger (Gloom Stalker): Iron Mind', 'Gain proficiency in Wisdom saving throws. If you already have it, gain proficiency in Intelligence or Charisma saving throws instead.'),
    ('Ranger (Gloom Stalker): Shadowy Dodge', 'Reaction when a creature makes an attack roll against you to impose Disadvantage on the roll, then teleport up to 30 feet whether the attack hits or misses.'),
    ('Ranger (Gloom Stalker): Stalker''s Flurry', 'Your Dreadful Strike becomes 2d8, and when you use it you can either attack a second nearby creature or force the target and nearby creatures to save or become Frightened.'),
    ('Ranger (Gloom Stalker): Umbral Sight', 'Gain Darkvision 60 feet, or increase existing Darkvision by 60 feet. While entirely in Darkness, you are Invisible to creatures relying on Darkvision to see you.'),
    ('Ranger (Hunter): Defensive Tactics', 'Choose Escape the Horde to impose Disadvantage on Opportunity Attacks against you or Multiattack Defense to impose Disadvantage on later attacks from a creature that hit you this turn. You can swap the option after a Short or Long Rest.'),
    ('Ranger (Hunter): Hunter''s Lore', 'While a creature is marked by your Hunter''s Mark, you know whether it has Immunities, Resistances, or Vulnerabilities, and what they are.'),
    ('Ranger (Hunter): Hunter''s Prey', 'Choose Colossus Slayer for extra damage against wounded foes or Horde Breaker for an extra attack against a nearby different creature. You can swap the option after a Short or Long Rest.'),
    ('Ranger (Hunter): Superior Hunter''s Defense', 'When you take damage, use a Reaction to gain Resistance to that damage and any other damage of the same type until the end of the current turn.'),
    ('Ranger (Hunter): Superior Hunter''s Prey', 'Once per turn when you damage a creature marked by Hunter''s Mark, also deal that spell''s extra damage to a different visible creature within 30 feet of the first.'),
    ('Ranger: Deft Explorer', 'Gain Expertise in one of your Ranger skill proficiencies and learn two languages of your choice.'),
    ('Ranger: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Ranger: Expertise', 'Choose two more skill proficiencies with which you lack Expertise. You gain Expertise in those skills.'),
    ('Ranger: Extra Attack', 'You can attack twice instead of once.'),
    ('Ranger: Favored Enemy', 'Always prepare Hunter''s Mark. You can cast it without a spell slot twice per Long Rest, gaining more free castings at higher Ranger levels.'),
    ('Ranger: Feral Senses', 'Gain Blindsight with a range of 30 feet.'),
    ('Ranger: Fighting Style', 'Gain a Fighting Style feat of your choice, or choose Druidic Warrior to learn two Druid cantrips using Wisdom.'),
    ('Ranger: Foe Slayer', 'The damage die of your Hunter''s Mark becomes a d10 instead of a d6.'),
    ('Ranger: Nature''s Veil', 'Bonus Action to give yourself the Invisible condition until the end of your next turn. Uses equal Wisdom modifier per Long Rest.'),
    ('Ranger: Precise Hunter', 'You have Advantage on attack rolls against the creature currently marked by your Hunter''s Mark.'),
    ('Ranger: Relentless Hunter', 'Taking damage cannot break your Concentration on Hunter''s Mark.'),
    ('Ranger: Roving', 'Your Speed increases by 10 feet while you are not wearing Heavy armor, and you gain Climb and Swim Speeds equal to your Speed.'),
    ('Ranger: Spellcasting', 'Cast prepared Ranger spells using Wisdom. You start with two level 1 prepared Ranger spells, and use a Druidic Focus as a spellcasting focus.'),
    ('Ranger: Tireless', 'Magic Action to gain Temporary Hit Points equal to 1d8 + Wisdom modifier a limited number of times per Long Rest. Your Exhaustion level also decreases by 1 whenever you finish a Short Rest.'),
    ('Ranger: Weapon Mastery', 'Use mastery properties for two weapons with which you have proficiency, changing your choices after each Long Rest.'),
    ('Rogue (Arcane Trickster): Mage Hand Legerdemain', 'When you cast Mage Hand, you can cast and control it as a Bonus Action, make the spectral hand Invisible, and use it to make Sleight of Hand checks.'),
    ('Rogue (Arcane Trickster): Magical Ambush', 'If you have the Invisible condition when you cast a spell on a creature, that creature has Disadvantage on saving throws against the spell on the same turn.'),
    ('Rogue (Arcane Trickster): Spell Thief', 'As a Reaction after a creature casts a spell that targets you or includes you in its area, force an Intelligence saving throw. On a failed save, the spell has no effect on you and you can temporarily steal it if it is a spell level you can cast.'),
    ('Rogue (Arcane Trickster): Spellcasting', 'You can cast prepared Wizard spells using Intelligence as your spellcasting ability. You know Mage Hand and two other Wizard cantrips, prepare Wizard spells, and can use an Arcane Focus.'),
    ('Rogue (Arcane Trickster): Versatile Trickster', 'When you use the Trip option of Cunning Strike on a creature, you can also use Trip on another creature within 5 feet of your Mage Hand.'),
    ('Rogue (Assassin): Assassin''s Tools', 'You gain a Disguise Kit and a Poisoner''s Kit, and you gain proficiency with both.'),
    ('Rogue (Assassin): Assassinate', 'You have Advantage on Initiative rolls. During the first round of combat, you have Advantage on attack rolls against any creature that has not taken a turn, and your Sneak Attack deals extra damage equal to your Rogue level.'),
    ('Rogue (Assassin): Death Strike', 'When you hit with Sneak Attack during the first round of combat, the target must succeed on a Constitution saving throw or the attack''s damage is doubled.'),
    ('Rogue (Assassin): Envenom Weapons', 'When you use the Poison option of Cunning Strike, the target also takes 2d6 Poison damage whenever it fails the saving throw, and the damage ignores Poison Resistance.'),
    ('Rogue (Assassin): Infiltration Expertise', 'You can mimic another person''s speech, handwriting, or both after studying them for at least 1 hour. Your Speed is no longer reduced to 0 by Steady Aim.'),
    ('Rogue (Soulknife): Psionic Power', 'You harbor a wellspring of psionic energy represented by Psionic Energy Dice. You can expend these dice to fuel Psi-Bolstered Knack and Psychic Whispers. You regain one expended die when you finish a Short Rest and all expended dice when you finish a Long Rest.'),
    ('Rogue (Soulknife): Psychic Blades', 'When you take the Attack action or make an Opportunity Attack, you can manifest a Psychic Blade with the Finesse and Thrown properties and the Vex mastery. After attacking with the blade on your turn, you can make a second Psychic Blade attack as a Bonus Action if your other hand is free.'),
    ('Rogue (Soulknife): Psychic Veil', 'As a Magic action, you gain the Invisible condition for 1 hour or until you dismiss the effect, deal damage, or force a creature to make a saving throw. Once you use this feature, you cannot use it again until you finish a Long Rest unless you expend a Psionic Energy Die.'),
    ('Rogue (Soulknife): Rend Mind', 'When your Psychic Blades deal Sneak Attack damage, you can force the target to make a Wisdom saving throw. On a failed save, the target has the Stunned condition for 1 minute. Once you use this feature, you cannot use it again until you finish a Long Rest unless you expend three Psionic Energy Dice.'),
    ('Rogue (Soulknife): Soul Blades', 'You can spend Psionic Energy Dice to teleport with Psychic Teleportation or improve missed Psychic Blade attacks with Homing Strikes.'),
    ('Rogue (Thief): Fast Hands', 'As a Bonus Action, you can make a Dexterity (Sleight of Hand) check to pick a lock, disarm a trap, or pick a pocket, or you can take the Utilize action or the Magic action to use a magic item.'),
    ('Rogue (Thief): Second-Story Work', 'You gain a Climb Speed equal to your Speed, and you can use Dexterity instead of Strength to determine your jump distance.'),
    ('Rogue (Thief): Supreme Sneak', 'You gain the Stealth Attack option for Cunning Strike, allowing an attack from hiding to avoid ending the Invisible condition if you end the turn behind strong cover.'),
    ('Rogue (Thief): Thief''s Reflexes', 'You can take two turns during the first round of any combat.'),
    ('Rogue (Thief): Use Magic Device', 'You can attune to up to four magic items, sometimes avoid spending item charges, and use any Spell Scroll with Intelligence as your spellcasting ability.'),
    ('Rogue: Cunning Action', 'Your quick thinking and agility allow you to move and act quickly. On your turn, you can take the Dash, Disengage, or Hide action as a Bonus Action.'),
    ('Rogue: Cunning Strike', 'You have developed cunning ways to use your Sneak Attack. When you deal Sneak Attack damage, you can forgo some of the extra dice to cause one Cunning Strike effect. Poison. Cost: 1d6. The target must succeed on a Constitution saving throw or have the Poisoned condition for 1 minute. Trip. Cost: 1d6. If the target is Large or smaller, it must succeed on a Dexterity saving throw or have the Prone condition. Withdraw. Cost: 1d6. Immediately after the attack, you move up to half your Speed without provoking Opportunity Attacks.'),
    ('Rogue: Devious Strikes', 'You have practiced new ways to use your Cunning Strike. Daze. Cost: 2d6. The target must succeed on a Constitution saving throw or on its next turn it can do only one of the following: move or take an action or Bonus Action. Knock Out. Cost: 6d6. The target must succeed on a Constitution saving throw or have the Unconscious condition for 1 minute. Obscure. Cost: 3d6. The target must succeed on a Dexterity saving throw or have the Blinded condition until the end of its next turn.'),
    ('Rogue: Elusive', 'No attack roll has Advantage against you while you do not have the Incapacitated condition.'),
    ('Rogue: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Rogue: Evasion', 'When you are subjected to an effect that allows you to make a Dexterity saving throw to take only half damage, you instead take no damage if you succeed on the saving throw and only half damage if you fail. You cannot use this feature if you have the Incapacitated condition.'),
    ('Rogue: Expertise', 'Choose two of your skill proficiencies to gain Expertise in those skills. At Rogue level 6, choose two more of your skill proficiencies to gain Expertise.'),
    ('Rogue: Improved Cunning Strike', 'You can use up to two Cunning Strike effects when you deal Sneak Attack damage, paying the die cost for each effect.'),
    ('Rogue: Reliable Talent', 'Whenever you make an ability check using one of your skill or tool proficiencies, treat a d20 roll of 9 or lower as a 10.'),
    ('Rogue: Slippery Mind', 'You gain proficiency in Wisdom and Charisma saving throws.'),
    ('Rogue: Sneak Attack', 'Once per turn, you can deal extra damage to one creature you hit with an attack roll if the attack uses a Finesse or Ranged weapon and you have Advantage on the attack roll. You do not need Advantage if at least one of your allies is within 5 feet of the target, the ally does not have the Incapacitated condition, and you do not have Disadvantage on the attack roll.'),
    ('Rogue: Steady Aim', 'As a Bonus Action, you give yourself Advantage on your next attack roll on the current turn. You can use this only if you have not moved during this turn, and after you use it, your Speed is 0 until the end of the current turn.'),
    ('Rogue: Stroke of Luck', 'If you fail a D20 Test, you can turn the roll into a 20. Once you use this feature, you cannot use it again until you finish a Short or Long Rest.'),
    ('Rogue: Thieves'' Cant', 'You know Thieves'' Cant and one additional language of your choice.'),
    ('Rogue: Uncanny Dodge', 'When an attacker that you can see hits you with an attack roll, you can take a Reaction to halve the attack damage against you.'),
    ('Rogue: Weapon Mastery', 'Your training with weapons allows you to use the mastery properties of two weapons with which you have proficiency. Whenever you finish a Long Rest, you can change the kinds of weapons you chose.'),
    ('Sorcerer (Aberrant Sorcery): Psionic Sorcery', 'When you cast a level 1+ Psionic Spell, you can spend Sorcery Points equal to the spell''s level instead of using a slot. If you do, the spell needs no Verbal or Somatic components and no Material components unless consumed or costly.'),
    ('Sorcerer (Aberrant Sorcery): Psionic Spells', 'Always prepare Mind Sliver, Arms of Hadar, Calm Emotions, Detect Thoughts, and Dissonant Whispers; later add Hunger of Hadar, Sending, Evard''s Black Tentacles, Summon Aberration, Rary''s Telepathic Bond, and Telekinesis.'),
    ('Sorcerer (Aberrant Sorcery): Psychic Defenses', 'You have resistance to psychic damage and advantage on saves vs being charmed or frightened.'),
    ('Sorcerer (Aberrant Sorcery): Revelation in Flesh', 'Bonus Action to spend Sorcery Points and transform your body for 10 minutes, choosing options such as aquatic adaptation, flight, seeing invisible creatures, or squeezing through narrow spaces.'),
    ('Sorcerer (Aberrant Sorcery): Telepathic Speech', 'Bonus Action to form a telepathic link with a creature you can see within 30ft.'),
    ('Sorcerer (Aberrant Sorcery): Warping Implosion', 'Magic Action to teleport up to 120 feet, then force creatures within 30 feet of your previous space to save against Force damage and being pulled inward. Refresh after a Long Rest or by spending 5 Sorcery Points.'),
    ('Sorcerer (Clockwork Sorcery): Bastion of Law', 'Magic Action to spend 1 to 5 Sorcery Points and create a ward of d8s around yourself or another visible creature within 30 feet. The ward can spend dice to reduce damage.'),
    ('Sorcerer (Clockwork Sorcery): Clockwork Cavalcade', 'Magic Action to summon spirits of order in a 30-foot Cube, restoring up to 100 HP, repairing objects, and ending level 6 or lower spells on chosen creatures or objects. Refresh after a Long Rest or by spending 7 Sorcery Points.'),
    ('Sorcerer (Clockwork Sorcery): Clockwork Spells', 'Always prepare Aid, Alarm, Lesser Restoration, and Protection from Evil and Good; later add Dispel Magic, Protection from Energy, Freedom of Movement, Summon Construct, Greater Restoration, and Wall of Force.'),
    ('Sorcerer (Clockwork Sorcery): Restore Balance', 'Reaction to prevent a creature within 60ft from having Advantage or Disadvantage on a roll.'),
    ('Sorcerer (Clockwork Sorcery): Trance of Order', 'Bonus Action to enter a 1-minute state in which attacks against you cannot benefit from Advantage and you can treat a d20 roll of 9 or lower as a 10 on D20 Tests. Refresh after a Long Rest or by spending 5 Sorcery Points.'),
    ('Sorcerer (Draconic Sorcery): Draconic Resilience', 'Your HP maximum increases by 3 and then by 1 whenever you gain another Sorcerer level. While unarmored, your base AC equals 10 + Dexterity modifier + Charisma modifier.'),
    ('Sorcerer (Draconic Sorcery): Draconic Resilience: Hit Points', 'Your HP maximum increases by 3 and then by 1 whenever you gain another Sorcerer level.'),
    ('Sorcerer (Draconic Sorcery): Draconic Spells', 'Always prepare Alter Self, Chromatic Orb, Command, and Dragon''s Breath; later add Fear, Fly, Arcane Eye, Charm Monster, Legend Lore, and Summon Dragon.'),
    ('Sorcerer (Draconic Sorcery): Dragon Companion', 'Cast Summon Dragon without a Material component and once per Long Rest without a spell slot. When you cast it, you can remove Concentration and reduce the duration to 1 minute.'),
    ('Sorcerer (Draconic Sorcery): Dragon Wings', 'Bonus Action to manifest draconic wings for 1 hour, gaining a 60-foot Fly Speed. Refresh after a Long Rest or by spending 3 Sorcery Points.'),
    ('Sorcerer (Draconic Sorcery): Elemental Affinity', 'Choose Acid, Cold, Fire, Lightning, or Poison as your draconic affinity. Gain Resistance to that type, and add Charisma to one damage roll of spells you cast that deal it.'),
    ('Sorcerer (Wild Magic Sorcery): Bend Luck', 'Reaction after a visible creature rolls a D20 Test; spend 1 Sorcery Point to add or subtract 1d4 from the roll.'),
    ('Sorcerer (Wild Magic Sorcery): Controlled Chaos', 'Whenever you roll on the Wild Magic Surge table, you can roll twice and use either result.'),
    ('Sorcerer (Wild Magic Sorcery): Tamed Surge', 'Immediately after casting a Sorcerer spell with a spell slot, choose an effect from the Wild Magic Surge table instead of rolling, except the final row. Refresh after a Long Rest.'),
    ('Sorcerer (Wild Magic Sorcery): Tides of Chaos', 'Gain Advantage on one D20 Test before rolling. Before you can use it again, you must finish a Long Rest or cast a Sorcerer spell with a spell slot, which automatically triggers a Wild Magic Surge roll.'),
    ('Sorcerer (Wild Magic Sorcery): Wild Magic Surge', 'Once per turn after casting a Sorcerer spell with a spell slot, roll 1d20. On a 20, roll on the Wild Magic Surge table.'),
    ('Sorcerer: Arcane Apotheosis', 'While Innate Sorcery is active, you can use one Metamagic option on each of your turns without spending Sorcery Points on it.'),
    ('Sorcerer: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Sorcerer: Font of Magic', 'Gain Sorcery Points equal to your Sorcerer level. Use them to create spell slots, convert slots into Sorcery Points, and fuel Sorcerer features.'),
    ('Sorcerer: Innate Sorcery', 'Bonus Action to awaken your innate magic for 1 minute. Your Sorcerer spell save DC increases by 1, and you have Advantage on attack rolls of Sorcerer spells.'),
    ('Sorcerer: Metamagic', 'Learn two Metamagic options that alter your spells. Whenever you gain a Sorcerer level, you can replace one option you know.'),
    ('Sorcerer: Sorcerous Restoration', 'Once per Long Rest when you finish a Short Rest, regain expended Sorcery Points up to half your Sorcerer level, rounded down.'),
    ('Sorcerer: Sorcery Incarnate', 'If you have no Innate Sorcery uses left, spend 2 Sorcery Points to activate it. While Innate Sorcery is active, you can use up to two Metamagic options on each spell you cast.'),
    ('Sorcerer: Spellcasting', 'Cast prepared Sorcerer spells using Charisma. You start with four Sorcerer cantrips and two level 1 prepared spells, and use an Arcane Focus as a spellcasting focus.'),
    ('Warlock (Archfey Patron): Archfey Spells', 'Always prepare Calm Emotions, Faerie Fire, Misty Step, Phantasmal Force, and Sleep; later add Blink, Plant Growth, Dominate Beast, Greater Invisibility, Dominate Person, and Seeming.'),
    ('Warlock (Archfey Patron): Beguiling Defenses', 'Gain Immunity to Charmed. When a visible creature hits you, use a Reaction to halve the damage and potentially deal Psychic damage back. Refresh after a Long Rest or by expending a Pact Magic slot.'),
    ('Warlock (Archfey Patron): Bewitching Magic', 'Immediately after casting an Enchantment or Illusion spell using an action and a spell slot, cast Misty Step as part of the same action without a spell slot.'),
    ('Warlock (Archfey Patron): Misty Escape', 'Cast Misty Step as a Reaction when you take damage. Add Disappearing Step and Dreadful Step to your Steps of the Fey options.'),
    ('Warlock (Archfey Patron): Steps of the Fey', 'Cast Misty Step without a spell slot a number of times equal to your Charisma modifier per Long Rest. When you cast it, add Refreshing Step or Taunting Step.'),
    ('Warlock (Celestial Patron): Celestial Resilience', 'Gain Temporary Hit Points when you use Magical Cunning or finish a Short or Long Rest. Up to five visible creatures also gain a smaller amount.'),
    ('Warlock (Celestial Patron): Celestial Spells', 'Always prepare Aid, Cure Wounds, Guiding Bolt, Lesser Restoration, Light, and Sacred Flame; later add Daylight, Revivify, Guardian of Faith, Wall of Fire, Greater Restoration, and Summon Celestial.'),
    ('Warlock (Celestial Patron): Healing Light', 'Gain a pool of d6s equal to 1 + Warlock level. As a Bonus Action, heal yourself or a visible creature within 60 feet, spending up to Charisma modifier dice.'),
    ('Warlock (Celestial Patron): Radiant Soul', 'Gain Resistance to Radiant damage. Once per turn when a spell you cast deals Radiant or Fire damage, add Charisma to that damage against one target.'),
    ('Warlock (Celestial Patron): Searing Vengeance', 'When you or an ally within 60 feet is about to make a Death Saving Throw, restore half that creature''s HP maximum, end Prone, and sear nearby chosen creatures with Radiant damage and Blinded. Once per Long Rest.'),
    ('Warlock (Fiend Patron): Dark One''s Blessing', 'When you reduce an enemy to 0 HP, or an enemy within 10 feet drops to 0 HP, gain Temporary Hit Points equal to Charisma modifier + Warlock level.'),
    ('Warlock (Fiend Patron): Dark One''s Own Luck', 'When you make an ability check or saving throw, add 1d10 after seeing the roll but before its effects. Uses equal Charisma modifier per Long Rest.'),
    ('Warlock (Fiend Patron): Fiend Spells', 'Always prepare Burning Hands, Command, Scorching Ray, and Suggestion; later add Fireball, Stinking Cloud, Fire Shield, Wall of Fire, Geas, and Insect Plague.'),
    ('Warlock (Fiend Patron): Fiendish Resilience', 'After each Short or Long Rest, choose one damage type other than Force and gain Resistance to it until you choose again.'),
    ('Warlock (Fiend Patron): Hurl Through Hell', 'Once per turn when you hit a creature, force a Charisma save or send it through the Lower Planes. It takes 8d10 Psychic damage if not a Fiend and is Incapacitated until it returns. Refresh after a Long Rest or by expending a Pact Magic slot.'),
    ('Warlock (Great Old One Patron): Awakened Mind', 'Bonus Action to form a telepathic bond with a visible creature within 30 feet for minutes equal to your Warlock level, working over miles equal to your Charisma modifier.'),
    ('Warlock (Great Old One Patron): Clairvoyant Combatant', 'When you form an Awakened Mind bond, force the target to make a Wisdom save. On a failure, it has Disadvantage against you and you have Advantage against it for the bond''s duration. Refresh after a Short or Long Rest or by expending a Pact Magic slot.'),
    ('Warlock (Great Old One Patron): Create Thrall', 'When you cast Summon Aberration, you can remove Concentration and reduce its duration to 1 minute. The Aberration gains Temporary Hit Points and deals extra Psychic damage to your Hex target once per turn.'),
    ('Warlock (Great Old One Patron): Eldritch Hex', 'Always prepare Hex. When you cast it and choose an ability, the target also has Disadvantage on saving throws with that ability.'),
    ('Warlock (Great Old One Patron): Great Old One Spells', 'Always prepare Detect Thoughts, Dissonant Whispers, Phantasmal Force, and Tasha''s Hideous Laughter; later add Clairvoyance, Hunger of Hadar, Confusion, Summon Aberration, Modify Memory, and Telekinesis.'),
    ('Warlock (Great Old One Patron): Psychic Spells', 'When a Warlock spell you cast deals damage, you can make it Psychic damage. When you cast an Enchantment or Illusion Warlock spell, it needs no Verbal or Somatic components.'),
    ('Warlock (Great Old One Patron): Thought Shield', 'Your thoughts cannot be read unless you allow it. Gain Resistance to Psychic damage, and creatures that deal Psychic damage to you take the same amount.'),
    ('Warlock: Contact Patron', 'Always prepare Contact Other Plane. Cast it once per Long Rest without a spell slot to contact your patron, automatically succeeding on the spell''s saving throw.'),
    ('Warlock: Eldritch Invocations', 'Gain one Eldritch Invocation, such as Pact of the Tome. Gain more invocations as you gain Warlock levels, and replace one whenever you gain a Warlock level.'),
    ('Warlock: Eldritch Master', 'When you use Magical Cunning, you regain all expended Pact Magic slots.'),
    ('Warlock: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Warlock: Magical Cunning', 'Perform a 1-minute rite to regain expended Pact Magic slots, up to half your maximum slots rounded up. Refresh after a Long Rest.'),
    ('Warlock: Mystic Arcanum', 'Choose one level 6 Warlock spell as an arcanum. Cast it once without a spell slot, regaining the use after a Long Rest.'),
    ('Warlock: Pact Magic', 'Cast prepared Warlock spells using Charisma. You start with two Warlock cantrips and two level 1 prepared spells, use an Arcane Focus, and regain Pact Magic slots on a Short or Long Rest.'),
    ('Wizard (Abjurer): Abjuration Savant', 'Add two Abjuration Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Abjuration Wizard spell of that level to your spellbook for free.'),
    ('Wizard (Abjurer): Arcane Ward', 'When you cast an Abjuration spell with a spell slot, create a ward with HP equal to twice your Wizard level plus Intelligence. The ward absorbs damage and can be restored by casting Abjuration spells or expending spell slots.'),
    ('Wizard (Abjurer): Projected Ward', 'Reaction to use your Arcane Ward to absorb damage for a creature within 30ft.'),
    ('Wizard (Abjurer): Spell Breaker', 'Always prepare Counterspell and Dispel Magic. Cast Dispel Magic as a Bonus Action, add Proficiency Bonus to its check, and do not expend a spell slot when Counterspell or Dispel Magic fails to stop a spell.'),
    ('Wizard (Abjurer): Spell Resistance', 'Gain advantage on saving throws against spells and resistance to damage from spells.'),
    ('Wizard (Diviner): Divination Savant', 'Add two Divination Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Divination Wizard spell of that level to your spellbook for free.'),
    ('Wizard (Diviner): Expert Divination', 'When you cast a divination spell of 2nd level or higher, regain a lower-level spell slot.'),
    ('Wizard (Diviner): Greater Portent', 'You now roll three d20s for your Portent feature instead of two.'),
    ('Wizard (Diviner): Portent', 'After each Long Rest, roll two d20s and record them. Before a visible creature makes a D20 Test, replace the roll with one recorded result, using each result once.'),
    ('Wizard (Diviner): The Third Eye', 'Bonus Action to gain one benefit until your next Short or Long Rest: 120-foot Darkvision, read any language, or cast See Invisibility without a spell slot.'),
    ('Wizard (Evoker): Empowered Evocation', 'Add your Intelligence modifier to one damage roll of any wizard evocation spell.'),
    ('Wizard (Evoker): Evocation Savant', 'Add two Evocation Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Evocation Wizard spell of that level to your spellbook for free.'),
    ('Wizard (Evoker): Overchannel', 'Deal maximum damage with a wizard spell of 1st through 5th level, but take necrotic damage if used again.'),
    ('Wizard (Evoker): Potent Cantrip', 'When you cast a damaging cantrip at a creature and miss or the creature succeeds on the save, it still takes half the cantrip''s damage but no other effect.'),
    ('Wizard (Evoker): Sculpt Spells', 'When you cast an Evocation spell that affects other visible creatures, choose a number of them equal to 1 plus the spell''s level. They automatically succeed on saves and take no damage on successful saves.'),
    ('Wizard (Illusionist): Illusion Savant', 'Add two Illusion Wizard spells of level 2 or lower to your spellbook. Whenever you gain access to a new spell slot level, add one Illusion Wizard spell of that level to your spellbook for free.'),
    ('Wizard (Illusionist): Illusory Reality', 'Bonus Action to make one object in your illusion become real and tangible for 1 minute.'),
    ('Wizard (Illusionist): Illusory Self', 'Reaction to create an illusory duplicate that causes an attack to automatically miss.'),
    ('Wizard (Illusionist): Improved Illusions', 'Cast Illusion spells without Verbal components, and increase their range by 60 feet if their range is 10 feet or more. You also know Minor Illusion, can cast it as a Bonus Action, and can create both sound and image with it.'),
    ('Wizard (Illusionist): Phantasmal Creatures', 'Always prepare Summon Beast and Summon Fey. When you cast either, you can make it Illusion, and once per Long Rest cast the Illusion version without a slot with the summoned creature at half HP.'),
    ('Wizard: Arcane Recovery', 'Once per Long Rest when you finish a Short Rest, recover expended spell slots with a combined level up to half your Wizard level, rounded up, none level 6 or higher.'),
    ('Wizard: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Wizard: Memorize Spell', 'Whenever you finish a Short Rest, study your spellbook and replace one prepared level 1+ Wizard spell with another level 1+ spell from the book.'),
    ('Wizard: Ritual Adept', 'Cast a spell as a ritual if it has the Ritual tag and is in your spellbook. The spell does not need to be prepared, but you must read from the book.'),
    ('Wizard: Scholar', 'Choose one proficient skill from Arcana, History, Investigation, Medicine, Nature, or Religion. You gain Expertise in that skill.'),
    ('Wizard: Signature Spells', 'Choose two 3rd-level spells as your signature spells, which you can cast without a slot once per rest.'),
    ('Wizard: Spell Mastery', 'Choose a 1st-level and 2nd-level spell to cast at their lowest level without expending a spell slot.'),
    ('Wizard: Spellcasting', 'Cast prepared Wizard spells using Intelligence. You start with three Wizard cantrips, a spellbook containing six level 1 Wizard spells, and four prepared level 1 spells. Use an Arcane Focus or your spellbook as a spellcasting focus.');

SELECT name, description
FROM _import_trait_data
ON CONFLICT (name) DO UPDATE SET description = EXCLUDED.description;

CREATE TEMP TABLE _import_class_trait_data (
    class_name TEXT NOT NULL,
    trait_name TEXT NOT NULL,
    level_required INT NOT NULL,
    PRIMARY KEY (class_name, trait_name, level_required)
) ON COMMIT DROP;


SELECT c.id, t.id, ctd.level_required
FROM _import_class_trait_data ctd
JOIN classes c ON c.name = ctd.class_name
JOIN traits t ON t.name = ctd.trait_name
ON CONFLICT (class_id, trait_id, level_required) DO NOTHING;

CREATE TEMP TABLE _import_subclass_trait_data (
    class_name TEXT NOT NULL,
    subclass_name TEXT NOT NULL,
    trait_name TEXT NOT NULL,
    level_required INT NOT NULL,
    PRIMARY KEY (class_name, subclass_name, trait_name, level_required)
) ON COMMIT DROP;


SELECT sc.id, t.id, std.level_required
FROM _import_subclass_trait_data std
JOIN classes c ON c.name = std.class_name
JOIN subclasses sc ON sc.class_id = c.id AND sc.name = std.subclass_name
JOIN traits t ON t.name = std.trait_name
ON CONFLICT (subclass_id, trait_id, level_required) DO NOTHING;

COMMIT;
