INSERT INTO _import_trait_data (name, description) VALUES
    ('Barbarian (Path of the Berserker): Frenzy', 'If you use Reckless Attack while your Rage is active, you deal extra damage to the first target you hit on your turn with a Strength-based attack. To determine the extra damage, roll a number of d6s equal to your Rage Damage bonus, and add them together. The damage has the same type as the weapon or Unarmed Strike used for the attack.'),
    ('Barbarian (Path of the Berserker): Intimidating Presence', 'As a Bonus Action, you can threaten nearby creatures. Each creature of your choice in a 30-foot Emanation must succeed on a Wisdom saving throw (DC 8 + your Strength modifier + your Proficiency Bonus) or have the Frightened condition for 1 minute. A frightened creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. Once you use this feature, you can''t use it again until you finish a Long Rest. You can also restore your use of this feature by expending one use of your Rage (no action required).'),
    ('Barbarian (Path of the Berserker): Mindless Rage', 'You are immune to the Charmed and Frightened conditions while your Rage is active. If you are Charmed or Frightened when you enter your Rage, the condition is suspended for the duration of the Rage.'),
    ('Barbarian (Path of the Berserker): Retaliation', 'Starting at 10th level, when you take damage from a creature that is within 5 feet of you, you can use your Reaction to make one melee attack against that creature with a weapon or an Unarmed Strike.'),
    ('Barbarian (Path of the Wild Heart): Animal Speaker', 'You can cast the Beast Sense and Speak with Animals spells, but only as rituals. Wisdom is your spellcasting ability for these spells.'),
    ('Barbarian (Path of the Wild Heart): Aspect of the Wilds', 'You gain an aspect of a beast. Whenever you finish a Long Rest, choose one of the following options, which lasts until you finish your next Long Rest: Owl. You gain Darkvision with a range of 60 feet. If you already have Darkvision, its range increases by 60 feet. Panther. You gain a Climb Speed equal to your Speed. Salmon. You gain a Swim Speed equal to your Speed.'),
    ('Barbarian (Path of the Wild Heart): Nature Speaker', 'You can cast the Commune with Nature spell, but only as a ritual. Wisdom is your spellcasting ability for this spell.'),
    ('Barbarian (Path of the Wild Heart): Power of the Wilds', 'You channel a magical aspect of a beast. Whenever you enter your Rage, choose one of the following options: Falcon. While you aren''t wearing armor, you gain a Fly Speed equal to your Speed. Lion. While your Rage is active, any enemy within 5 feet of you has Disadvantage on attack rolls against targets other than you or another character with this feature. Ram. While your Rage is active, if you hit a Large or smaller creature with a melee attack, you can knock the target Prone.'),
    ('Barbarian (Path of the Wild Heart): Rage of the Wilds', 'You channel the power of a beast. Whenever you enter your Rage, choose one of the following options: Bear. While your Rage is active, you have Resistance to all damage types except Force, Necrotic, Psychic, and Radiant. Eagle. When you enter your Rage, and as a Bonus Action while your Rage is active, you can take both the Dash and Disengage actions. Wolf. While your Rage is active, your allies have Advantage on melee attack rolls against any enemy within 5 feet of you that is not Incapacitated.'),
    ('Barbarian (Path of the World Tree): Battering Roots', 'During your turn, the reach for your melee attacks with weapons that have the Heavy or Versatile property is 10 feet greater than normal. In addition, when you hit with such a weapon on your turn, you can activate its Push or Topple property even if you don''t have that property active for the weapon.'),
    ('Barbarian (Path of the World Tree): Branches of the Tree', 'While your Rage is active, when a creature you can see starts its turn within 30 feet of you, you can use your Reaction to summon spectral branches. The target must succeed on a Strength saving throw (DC 8 + your Strength modifier + your Proficiency Bonus) or be teleported to an unoccupied space you choose within 5 feet of yourself. Alternatively, you can teleport the willing target to that space without a saving throw. If the target fails the save (or is willing), its Speed is reduced to 0 until the end of the current turn.'),
    ('Barbarian (Path of the World Tree): Travel Along the Tree', 'When you enter your Rage and as a Bonus Action while your Rage is active, you can teleport up to 60 feet to an unoccupied space you can see. Once per Rage, you can increase this teleport''s range to 150 feet. When you do so, you can also bring up to six willing creatures of Medium size or smaller that are within 10 feet of you. Each creature is teleported to an unoccupied space of your choice within 10 feet of your destination space.'),
    ('Barbarian (Path of the World Tree): Vitality of the Tree', 'When you enter your Rage, you gain Temporary Hit Points equal to your Barbarian level. At the start of each of your turns while your Rage is active, you can choose another creature within 10 feet of yourself. That creature gains Temporary Hit Points equal to your Rage Damage bonus, which last until the start of your next turn.'),
    ('Barbarian (Path of the Zealot): Divine Fury', 'While your Rage is active, you can channel divine fury into your weapon strikes. The first creature you hit on each of your turns with a weapon or an Unarmed Strike takes extra damage. The extra damage is 1d6 plus half your Barbarian level (round down). The extra damage is Necrotic or Radiant (your choice when you hit the target).'),
    ('Barbarian (Path of the Zealot): Fanatical Focus', 'If you fail a saving throw while your Rage is active, you can reroll it, and you must use the new roll. You gain a bonus to the new roll equal to your Rage Damage bonus. Once you use this feature, you can''t use it again until you enter a new Rage.'),
    ('Barbarian (Path of the Zealot): Rage of the Gods', 'Your Rage becomes a manifest beacon of divine power. While your Rage is active, you gain the following benefits: Fly Speed. You gain a Fly Speed equal to your Speed, and you can hover. Resistances. You have Resistance to Necrotic, Psychic, and Radiant damage. Defy Death. If a creature you can see within 30 feet of you (including yourself) would drop to 0 Hit Points, you can use your Reaction to prevent it from doing so. The creature instead drops to 1 Hit Point.'),
    ('Barbarian (Path of the Zealot): Warrior of the Gods', 'A divine power protects you and others. You have a pool of d12s that you can use to restore Hit Points. The pool''s total number of dice equals your Barbarian level. As a Bonus Action, you can spend dice from the pool to heal yourself or a creature within 5 feet of you. Roll the spent dice, and the target regains a number of Hit Points equal to the roll''s total.'),
    ('Barbarian (Path of the Zealot): Zealous Presence', 'As a Bonus Action, you unleash a battle cry infused with divine energy. Up to ten other creatures of your choice within 60 feet of you gain Advantage on attack rolls and saving throws until the start of your next turn. Once you use this feature, you can''t use it again until you finish a Long Rest. You can also restore your use of this feature by expending one use of your Rage (no action required).'),
    ('Barbarian: Brutal Strike', 'If you use Reckless Attack, you can forgo any Advantage on one Strength-based attack roll of your choice on your turn. The chosen attack roll mustn’t have Disadvantage. If the chosen attack roll hits, the target takes an extra 1d10 damage of the same type dealt by the weapon or Unarmed Strike, and you can cause one Brutal Strike effect of your choice. Forceful Blow. The target is pushed 15 feet straight away from you. You can then move up to half your Speed straight toward the target without provoking Opportunity Attacks. Hamstring Blow. The target’s Speed is reduced by 15 feet until the start of your next turn. A target can be affected by only one Hamstring Blow at a time—the most recent one.'),
    ('Barbarian: Danger Sense', 'You gain an uncanny sense of when things aren’t as they should be, giving you an edge when you dodge perils. You have Advantage on Dexterity saving throws unless you have the Incapacitated condition.'),
    ('Barbarian: Epic Boon', 'You gain an Epic Boon feat or another feat for which you qualify.'),
    ('Barbarian: Extra Attack', 'You can attack twice instead of once whenever you take the Attack action on your turn.'),
    ('Barbarian: Fast Movement', 'Your speed increases by 10 feet while you are not wearing Heavy Armor.'),
    ('Barbarian: Feral Instinct', 'Your instincts are so honed that you have Advantage on Initiative rolls.'),
    ('Barbarian: Improved Brutal Strike', 'You have honed new ways to attack furiously. The following effects are now among your Brutal Strike options. Staggering Blow. The target has Disadvantage on the next saving throw it makes, and it can’t make Opportunity Attacks until the start of your next turn. Sundering Blow. Before the start of your next turn, the next attack roll made by another creature against the target gains a +5 bonus to the roll. An attack roll can gain only one Sundering Blow bonus.'),
    ('Barbarian: Indomitable Might', 'If your total for a Strength check or Strength saving throw is less than your Strength score, you can use that score in place of the total.'),
    ('Barbarian: Instinctive Pounce', 'As part of the Bonus Action you take to enter your Rage, you can move up to half your Speed.'),
    ('Barbarian: Persistent Rage', 'When you roll Initiative, you can regain all expended uses of Rage. After you regain uses of Rage in this way, you can’t do so again until you finish a Long Rest. In addition, your Rage is so fierce that it now lasts for 10 minutes without you needing to do anything to extend it from round to round. Your Rage ends early if you have the Unconscious condition (not just the Incapacitated condition) or don Heavy armor.'),
    ('Barbarian: Primal Champion', 'You embody primal power. Your Strength and Constitution scores increase by 4, and their maximum is now 25.'),
    ('Barbarian: Primal Knowledge', 'You gain proficiency in another skill of your choice from the skill list available to Barbarians at level 1. In addition, while your Rage is active, you can channel primal power when you attempt certain tasks; whenever you make an ability check using one of the following skills, you can make it as a Strength check even if it normally uses a different ability: Acrobatics, Intimidation, Perception, Stealth, or Survival. When you use this ability, your Strength represents primal power coursing through you, honing your agility, bearing, and senses.'),
    ('Barbarian: Rage', 'You can imbue yourself with a primal power called Rage, a force that grants you extraordinary might and resilience. You can enter it as a Bonus Action if you aren’t wearing Heavy armor. You can enter your Rage the number of times shown for your Barbarian level in the Rages column of the Barbarian Features table. You regain one expended use when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest. While active, your Rage follows the rules below. Damage Resistance. You have Resistance to Bludgeoning, Piercing, and Slashing damage. Rage Damage. When you make an attack using Strength—with either a weapon or an Unarmed Strike—and deal damage to the target, you gain a bonus to the damage that increases as you gain levels as a Barbarian, as shown in the Rage Damage column of the Barbarian Features table. Strength Advantage. You have Advantage on Strength checks and Strength saving throws. No Concentration or Spells. You can’t maintain Concentration, and you can’t cast spells. Duration. The Rage lasts until the end of your next turn, and it ends early if you don Heavy armor or have the Incapacitated condition. If your Rage is still active on your next turn, you can extend the Rage for another round by doing one of the following:
INSERT INTO traits (name, description)
